    assign n = 5; // Number of data points

    always @(*) begin
  // Calculate slope (m) = (n*Σxy - Σx*Σy) / (n*Σx^2 - (Σx)^2) slope = (n * sum_xy - sum_x * sum_y) / (n * sum_x2 - sum_x * sum_x) ;
  end

  always @(*) begin
  // Calculate intercept (b) = (Σy - slope*Σx) / n intercept = (sum_y - slope * sum_x) / n ;
