module top_module(
    input clk,
    input reset,
    input [15:0] in,
    output reg [7:0] out_sum);// Split input into two 8-bit outputs using a barrel shifter
    reg [7:0] upper_out;
    reg [7:0] lower_out;
    always @(*) begin
  upper_out = in >> 8 ;
  end

  always @(*) begin
  lower_out = in & 8'hFF ;
  end

    // 4-bit binary counter
    reg [3:0] counter;
    always @(posedge clk) begin
        if (reset) begin
            counter <= 4'h0;
        end else if (counter == 4'hF) begin
            counter <= 4'h0;
        end else begin
            counter <= counter + 1;
        end
    end

    // Adder to sum the two values
    reg [7:0] sum;
    always @(*) begin
        sum = upper_out + counter + lower_out;
    end

    // Output the sum
    always @(posedge clk) begin
        if (reset) begin
            out_sum <= 8'h0;
        end else begin
            out_sum <= sum;
        end
    end

endmodule

module top_module(output reg signed[15:0] CR, output reg AR_gt_0, AR_lt_0,input [15:0] Data_AR, Data_BR,input Ld_AR_BR, Div_AR_x2_CR, Mul_BR_x2_CR, Clr_CR, clk);reg signed [15:0] AR; 
  reg signed [15:0] BR; 
  always @(AR) begin
  AR_lt_0 = (AR < 0) ;
  end

  always @(AR) begin
  AR_gt_0 = (AR > 0) ;
  end 
  always @(negedge clk) begin 
  if (Ld_AR_BR) begin 
  AR = Data_AR; 
  BR = Data_BR; 
  end else if (Div_AR_x2_CR) begin 
  CR = AR / 2; 
  end else if (Mul_BR_x2_CR) begin 
  CR = BR * 2; 
  end else if (Clr_CR) begin 
  CR = 0; 
  end 
  end 
 endmodule

