	input [31:0] rda, rdb;
	output  [31:0] a, b;
	reg [31:0] a,b;
	always @(posedge clk) begin
  a <= rda ;
  end

  always @(posedge clk) begin
  b <= rdb ;
  end

endmodule

module top_module(
    input                       clk,

    input       [widthad-1:0]   wraddress,
    input                       wren,
    input       [width-1:0]     data,

    input       [widthad-1:0]   rdaddress,
    output reg  [width-1:0]     q
);parameter width     = 1;
parameter widthad   = 1;

reg [width-1:0] mem [(2**widthad)-1:0];

always @(posedge clk) begin
  if(wren) mem[wraddress] <= data ;
  end

  always @(posedge clk) begin
  q <= mem[rdaddress] ;
  end

endmodule

module top_module(in, out, inAddr, outAddr, writeSel, clk);parameter depth=1024, width=16, logDepth=10;

   input [width-1:0]    in;
   input [logDepth-1:0] inAddr, outAddr;
   input 	        writeSel, clk;
   output [width-1:0] 	out;
   reg [width-1:0] 	out;

   // synthesis attribute ram_style of mem is distributed

   reg [width-1:0] 	mem[depth-1:0]; 

   always @(posedge clk) begin
  out <= mem[outAddr] ;
  end

  always @(posedge clk) begin
  if (writeSel) mem[inAddr] <= in ;
  end
endmodule

module top_module(
  input a,
  input b,
  input clk,
  output reg out
);reg delayed_a;
  reg delayed_b;

  always @(posedge clk) begin
  delayed_a <= a ;
  end

  always @(posedge clk) begin
  delayed_b <= b ;
  end

  always @(posedge clk) begin
    out <= delayed_a & delayed_b;
  end

endmodule

module regfile_32bit_8reg (read_data1, read_data2, clk, reset, read_addr1, read_addr2, write_addr, write_en, write_data);
   input clk, reset;
   input [2:0] read_addr1, read_addr2, write_addr;
   input write_en;
   input [31:0] write_data;
   output [31:0] read_data1, read_data2;

   reg [31:0] registers [7:0];
   reg [31:0] read_data1, read_data2;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        registers[0] <= 32'b0;
        registers[1] <= 32'b0;
        registers[2] <= 32'b0;
        registers[3] <= 32'b0;
        registers[4] <= 32'b0;
        registers[5] <= 32'b0;
        registers[6] <= 32'b0;
        registers[7] <= 32'b0;
    end 
    else if (write_en) 
        registers[write_addr] <= write_data;
end

always @(*) begin
  read_data1 = registers[read_addr1] ;
  end

  always @(*) begin
  read_data2 = registers[read_addr2] ;
  end

endmodule

module top_module(
    input [3:0] data1,
    input [3:0] data2,
    input [1:0] op,
    input clk,         // Added clk input
    output reg [3:0] q
);reg [3:0] stage1_out;
reg [3:0] stage2_out;

always @(*) begin
    case(op)
        2'b00: stage1_out = data1 + data2;
        2'b01: stage1_out = data1 - data2;
        2'b10: stage1_out = data1 & data2;
        2'b11: stage1_out = data1 | data2;
        default: stage1_out = 4'b0000; // Added default case
    endcase
end

always @(posedge clk) begin
  stage2_out <= stage1_out ;
  end

  always @(posedge clk) begin
  q <= stage2_out ;
  end

endmodule

module top_module(input A, B, output reg q_nand, q_nor, q_xnor, q_not);always @(A, B) begin
  q_nand = A ~& B ;
  end

  always @(A, B) begin
  q_nor = A ~| B ;
  q_xnor = A ~^ B ;
  q_not = ~A ;
  end

endmodule

