module tbu
(
   clk,
   rst,
   enable,
   selection,
   d_in_0,
   d_in_1,
   d_o,
   wr_en
);
   input       clk;
   input       rst;
   input       enable;
   input       selection;
   input [7:0] d_in_0;
   input [7:0] d_in_1;
   output reg  d_o;
   output reg  wr_en;
   reg         d_o_reg;
   reg         wr_en_reg;
   reg   [2:0] pstate;
   reg   [2:0] nstate;
   reg         selection_buf;
   always @(posedge clk) begin
  selection_buf <= selection ;
  end

  always @(posedge clk) begin
  wr_en <= wr_en_reg ;
  d_o <= d_o_reg ;
  end
   always @(posedge clk or negedge rst)
   begin
      if(rst==1'b0)
         pstate   <= 3'b000;
      else if(enable==1'b0)
         pstate   <= 3'b000;
      else if(selection_buf==1'b1 && selection==1'b0)
         pstate   <= 3'b000;
      else
         pstate   <= nstate;
   end
   always @(*)
   begin
      case (pstate)
         3'b000:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[0])
                  1'b0: nstate   =  3'b000;
                  1'b1: nstate   =  3'b001;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[0];  
               wr_en_reg =  1'b1;
               case(d_in_1[0])
                  1'b0: nstate   =  3'b000;
                  1'b1: nstate   =  3'b001;
               endcase
           end
         end
         3'b001:
         begin
            if(selection==1'b0)
             begin
             wr_en_reg =  1'b0;
               case(d_in_0[1])
                  1'b0: nstate   =  3'b011;
                  1'b1: nstate   =  3'b010;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[1];  
               wr_en_reg =  1'b1;
               case(d_in_1[1])
                  1'b0: nstate   =  3'b011;
                  1'b1: nstate   =  3'b010;
               endcase
           end
         end
         3'b010:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[2])
                  1'b0: nstate   =  3'b100;
                  1'b1: nstate   =  3'b101;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[2];  
               wr_en_reg =  1'b1;
               case(d_in_1[2])
                  1'b0: nstate   =  3'b100;
                  1'b1: nstate   =  3'b101;
               endcase
            end
         end
         3'b011:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[3])
                  1'b0: nstate   =  3'b111;
                  1'b1: nstate   =  3'b110;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[3]; 
               wr_en_reg =  1'b1;
               case(d_in_1[3])
                  1'b0: nstate   =  3'b111;
                  1'b1: nstate   =  3'b110;
               endcase
            end
         end
         3'b100:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[4])
                  1'b0: nstate   =  3'b001;
                  1'b1: nstate   =  3'b000;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[4];  
               wr_en_reg =  1'b1;
               case(d_in_1[4])
                  1'b0: nstate   =  3'b001;
                  1'b1: nstate   =  3'b000;
               endcase
            end
         end
         3'b101:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[5])
                  1'b0: nstate   =  3'b010;
                  1'b1: nstate   =  3'b011;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[5];  
               wr_en_reg =  1'b1;
               case(d_in_1[5])
                  1'b0: nstate   =  3'b010;
                  1'b1: nstate   =  3'b011;
               endcase
            end
         end
         3'b110:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[6])
                  1'b0: nstate   =  3'b101;
                  1'b1: nstate   =  3'b100;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[6];  
               wr_en_reg =  1'b1;
               case(d_in_1[6])
                  1'b0: nstate   =  3'b101;
                  1'b1: nstate   =  3'b100;
               endcase
            end
         end
         3'b111:
         begin
            if(selection==1'b0)
            begin
               wr_en_reg =  1'b0;
               case(d_in_0[7])
                  1'b0: nstate   =  3'b110;
                  1'b1: nstate   =  3'b111;
               endcase
            end
            else
            begin
               d_o_reg   =  d_in_1[7];  
               wr_en_reg =  1'b1;
               case(d_in_1[7])
                  1'b0: nstate   =  3'b110;
                  1'b1: nstate   =  3'b111;
               endcase
            end
         end
      endcase
   end
endmodule

module gng_smul_16_18_sadd_37 (
    input clk,                  
    input [15:0] a,             
    input [17:0] b,             
    input [36:0] c,             
    output [37:0] p             
);
reg signed [15:0] a_reg;
reg signed [17:0] b_reg;
reg signed [36:0] c_reg;
reg signed [33:0] prod;
wire signed [37:0] sum;
reg [37:0] result;
always @ (posedge clk) begin
  a_reg <= a ;
  end

  always @ (posedge clk) begin
  b_reg <= b ;
  c_reg <= c ;
  end
always @ (posedge clk) begin
    prod <= a_reg * b_reg;
end
assign sum = c_reg + prod;
always @ (posedge clk) begin
    result <= sum;
end
assign p = result;
endmodule

module LED(
    input  clock,
    input  reset,
    input  [14:0] dataIn,
    input  [7:0] IP,
    input  Write,
    input  Read,
    output [13:0] dataOut,
    output reg Ack,
    output [13:0] LED
    );
    reg  [13:0] data;
    reg  useInterrupts;
    always @(posedge clock) begin
  data <= (reset) ? 14'b0 : ((Write) ? dataIn[13:0] : data) ;
  end

  always @(posedge clock) begin
  useInterrupts <= (reset) ? 0 : ((Write) ? dataIn[14] : useInterrupts) ;
  end
    always @(posedge clock) begin
        Ack <= (reset) ? 0 : (Write | Read);
    end
    assign LED = (useInterrupts) ? {6'b0, IP[7:0]} : data;
    assign dataOut = data;
endmodule

module hvsync_gen(
			clk,
			h_sync,
			v_sync,
			wcntX,
			wcntY
		 );
input clk;
output h_sync;
output v_sync;
output [9:0] wcntX;
output [8:0] wcntY;
parameter PIXEL_CLOCK = 25;
parameter GLOBAL_CLOCK = 50;
parameter MULT_FACTOR = GLOBAL_CLOCK / PIXEL_CLOCK;
parameter VGA_H_SYNC_PULSE  = 96 * MULT_FACTOR;
parameter VGA_H_FRONT_PORCH = 16 * MULT_FACTOR;
parameter VGA_H_BACK_PORCH  = 48 * MULT_FACTOR;
parameter VGA_H_PIXEL_COUNT = 800 * MULT_FACTOR;
parameter VGA_V_SYNC_PULSE  = 2;
parameter VGA_V_FRONT_PORCH = 10;
parameter VGA_V_BACK_PORCH  = 33;
parameter VGA_V_LINE_COUNT  = 525;
reg vga_HS;
reg vga_VS;
reg [10:0] cntX;
reg [9:0]  cntY;
reg [9:0] wcntX;
reg [8:0] wcntY;
wire cntXmaxed = (cntX == VGA_H_PIXEL_COUNT - 1);
wire cntYmaxed = (cntY == VGA_V_LINE_COUNT - 1);
always @(posedge clk) begin
	if(cntYmaxed) begin
			 cntY <= 0;
			wcntY <= 0;
	end
	if(cntXmaxed) begin
	     cntX <= 0;
		  cntY <= cntY + 1;
		 wcntX <= 0;		  
	 	 if (   (cntY > VGA_V_SYNC_PULSE + VGA_V_FRONT_PORCH) 
		 	  && (cntY < VGA_V_LINE_COUNT - VGA_V_BACK_PORCH)
				)
		 begin
		     wcntY <= wcntY + 1;
		 end
	end
	else begin
		 if (   (cntX[10:0] > VGA_H_SYNC_PULSE + VGA_H_FRONT_PORCH) 
			  && (cntX[10:0] < VGA_H_PIXEL_COUNT  - VGA_H_BACK_PORCH) 
			  && (cntX[0] == 0)  
			 ) 
		  begin
				wcntX <= wcntX + 1;
		  end
		  cntX <= cntX + 1;
	end
end
always @(posedge clk) begin
  vga_HS <= (cntX[10:0] < VGA_H_SYNC_PULSE) ;
  end

  always @(posedge clk) begin
  vga_VS <= (cntY[9:0] < VGA_V_SYNC_PULSE) ;
  end
assign h_sync = ~vga_HS;
assign v_sync = ~vga_VS;
endmodule

module two_bit_encoder (
    input [1:0] data,
    output reg q,
    output reg zero
);

    always @(*) begin
  q = data[1] ;
  end

  always @(*) begin
  zero = ~(|data) ;
  end

endmodule

module my_module(
    input [3:0] A,
    input [3:0] B,
    input [3:0] C,
    input [3:0] D,
    input [3:0] E,
    output reg X
);

    reg [3:0] sum;
    reg [3:0] max;

    always @* begin
  sum = A + B + C + D + E ;
  end

  always @* begin
  max = A ;
  if (B > max) max = B ;
  if (C > max) max = C ;
  if (D > max) max = D ;
  if (E > max) max = E ;
  end

    always @(sum, max)
    begin
        if (sum >= max) X = 1;
        else X = 0;
    end

endmodule

module binary_adder(
    input [3:0] A,
    input [3:0] B,
    input CIN,
    output reg [3:0] S,
    output reg COUT
);

    reg CARRY;

    always @(*) begin
  S[0] = A[0] ^ B[0] ^ CIN ;
  S[1] = A[1] ^ B[1] ^ CARRY ;
  S[2] = A[2] ^ B[2] ^ CARRY ;
  S[3] = A[3] ^ B[3] ^ CARRY ;
  end

  always @(*) begin
  CARRY = (A[0] & B[0]) | (A[0] & CIN) | (B[0] & CIN) ;
  CARRY = (A[1] & B[1]) | (A[1] & CARRY) | (B[1] & CARRY) ;
  CARRY = (A[2] & B[2]) | (A[2] & CARRY) | (B[2] & CARRY) ;
  COUT = (A[3] & B[3]) | (A[3] & CARRY) | (B[3] & CARRY) ;
  end

endmodule

